import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it("should return empty grid for empty grid", () => {
    expect(nextGeneration([])).toEqual([]);
  });
  it("should return empty grid for single live cell (underpopulation)", () => {
    expect(nextGeneration([[1]])).toEqual([]);
  });
  it("should return empty grid for two live cells (underpopulation)", () => {
    expect(nextGeneration([[1, 1]])).toEqual([]);
  });
  it("should keep a live cell alive when it has exactly 2 live neighbors", () => {
    expect(nextGeneration([[1, 1, 1]])).toEqual([[0, 1, 0]]);
  });
  it.todo("should keep a live cell alive when it has exactly 3 live neighbors");
  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
  it.todo("should reproduce a dead cell with exactly 3 live neighbors");
  it.todo("should transform a blinker (3 cells in a row) to next generation (3 cells in a column)");
  it.todo("should keep a block (2x2 square) unchanged as a still life");
});
